UPDATE TB_REVIEW
   SET BIZ_REPLY = #{bizReply, jdbcType=VARCHAR}
 WHERE REVIEW_TYPE = 'HOSPITAL'
   AND TARGET_ID = #{hospitalId}
   AND REVIEW_ID = #{reviewId}

UPDATE TB_HOSPITAL_TREAT_TYPE
   SET TYPE_NAME    = #{typeName, jdbcType=VARCHAR},
       DURATION_MIN = #{durationMin, jdbcType=NUMERIC},
       STATUS_CD    = #{statusCd, jdbcType=VARCHAR},
       SORT_ORDR    = #{sortOrdr, jdbcType=NUMERIC}
 WHERE HOSPITAL_ID  = #{hospitalId}
   AND TREAT_TYPE_ID = #{treatTypeId}

mapper.delete:
DELETE FROM TB_HOSPITAL_TREAT_TYPE
 WHERE HOSPITAL_ID = #{hospitalId}
   AND TREAT_TYPE_ID = #{treatTypeId}

