       SPECIALTY   = #{specialty, jdbcType=VARCHAR},
       STATUS_CD   = #{statusCd, jdbcType=VARCHAR},
       SORT_ORDR   = #{sortOrdr, jdbcType=NUMERIC}
 WHERE HOSPITAL_ID = #{hospitalId}
   AND DOCTOR_ID   = #{doctorId}

